            aOrbiterE = (aOrbiterE + aOrbiterC) + 0xD86F0C60FA3CE2B8ULL;
            aOrbiterH = ((aOrbiterH ^ aOrbiterE) ^ 0xFEE1346891ADEF7AULL) ^ aPhaseGOrbiterUpdateSaltE[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 0x7369CF0A044B485BULL), 39U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterE) + 0x9CB16178685D2948ULL) + aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 20U)) & S_SALT1];
