            aWandererA = aWandererA + (((RotL64(aScatter, 41U) + aOrbiterC) + RotL64(aOrbiterK, 21U)) + RotL64(aCarry, 19U));
            aWandererJ = aWandererJ ^ ((RotL64(aPrevious, 21U) + RotL64(aOrbiterD, 19U)) + aOrbiterF);
